export interface Citation {
  section: string;
  page: number;
  quote: string;
}

export interface TableData {
  id: string;
  caption: string;
  page: number;
  headers: string[];
  rows: (string | number)[][];
  validated: boolean;
  csv: string;
}

export interface InfographicAsset {
  id: string;
  title: string;
  source_table_id: string;
  source_page: number;
