// @ts-ignore
const pdfjsLib = window['pdfjs-dist/build/pdf'];
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

export async function extractTextFromPDF(file: File): Promise<{ pageNumber: number; text: string }[]> {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  const pages: { pageNumber: number; text: string }[] = [];

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const strings = content.items.map((item: any) => item.str);
    pages.push({
      pageNumber: i,
      text: strings.join(' '),
    });
  }

  return pages;
}

import { TableData, InfographicAsset } from '../types';

export function generateSVGChart(table: TableData): InfographicAsset | null {
  if (!table.validated || table.rows.length < 1 || table.headers.length < 2) return null;

  // Simple Bar Chart Generator
  const width = 600;
  const height = 400;
  const margin = { top: 40, right: 30, bottom: 60, left: 60 };
  const innerWidth = width - margin.left - margin.right;
  const innerHeight = height - margin.top - margin.bottom;

  // Identify numeric column for Y-axis (first numeric column found after index 0)
  let numericColIdx = -1;
  for (let i = 1; i < table.headers.length; i++) {
    if (table.rows.every(row => !isNaN(Number(row[i])))) {
      numericColIdx = i;
      break;
    }
  }

  if (numericColIdx === -1) return null;

  const data = table.rows.map(row => ({
    label: String(row[0]).slice(0, 15),
    value: Number(row[numericColIdx])
  }));

  const maxValue = Math.max(...data.map(d => d.value), 0) * 1.1;
  const barWidth = (innerWidth / data.length) * 0.8;
  const barGap = (innerWidth / data.length) * 0.2;

  const bars = data.map((d, i) => {
    const barHeight = (d.value / maxValue) * innerHeight;
    const x = margin.left + i * (barWidth + barGap);
    const y = margin.top + innerHeight - barHeight;

    return `
      <rect x="${x}" y="${y}" width="${barWidth}" height="${barHeight}" fill="#4F46E5" rx="4" />
      <text x="${x + barWidth / 2}" y="${height - margin.bottom + 20}" text-anchor="middle" font-size="12" fill="#374151" transform="rotate(30, ${x + barWidth / 2}, ${height - margin.bottom + 20})">${d.label}</text>
    `;
  }).join('');

  // Y-axis ticks
  const ticks = [0, maxValue / 4, maxValue / 2, (maxValue * 3) / 4, maxValue].map(v => {
    const y = margin.top + innerHeight - (v / maxValue) * innerHeight;
    return `
      <line x1="${margin.left - 5}" y1="${y}" x2="${margin.left}" y2="${y}" stroke="#9CA3AF" />
      <text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" font-size="10" fill="#6B7280">${v.toFixed(1)}</text>
    `;
  }).join('');

  const svg = `
    <svg width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg">
      <rect width="100%" height="100%" fill="transparent" />
      <line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + innerHeight}" stroke="#E5E7EB" />
      <line x1="${margin.left}" y1="${margin.top + innerHeight}" x2="${margin.left + innerWidth}" y2="${margin.top + innerHeight}" stroke="#E5E7EB" />
      <text x="${width / 2}" y="${margin.top / 2 + 10}" text-anchor="middle" font-weight="bold" font-size="16" fill="#111827">${table.caption}</text>
      ${ticks}
      ${bars}
    </svg>
  `;

  return {
    id: `chart_${table.id}`,
    title: table.caption,
    source_table_id: table.id,
    source_page: table.page,
    svg: svg
  };
}

import { GoogleGenAI, Type } from "@google/genai";
import { InfographicData, TableData, Citation } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function analyzePaper(pages: { pageNumber: number; text: string }[]): Promise<InfographicData> {
  const fullText = pages.map(p => `Page ${p.pageNumber}: ${p.text}`).join('\n\n');
  const modelName = 'gemini-3-pro-preview';

  const response = await ai.models.generateContent({
    model: modelName,
    contents: `Analyze the following research paper text and extract information for a self-contained infographic.

    Constraints:
    - No invented facts.
    - Every claim must have a citation (page number and short quote).
    - Identify any tabular data for chart generation.
    - Be concise and clear.

    PAPER TEXT:
    ${fullText.slice(0, 30000)} // Truncated for token limits, but enough for most papers
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          researchQuestion: { type: Type.STRING },
          methodology: { type: Type.STRING },
          keyFindings: { type: Type.STRING },
          limitations: { type: Type.STRING },
          contributions: { type: Type.STRING },
          citations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                section: { type: Type.STRING },
                page: { type: Type.NUMBER },
                quote: { type: Type.STRING }
              },
              required: ["section", "page", "quote"]
            }
          },
          tables: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                caption: { type: Type.STRING },
                page: { type: Type.NUMBER },
                headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } }
              },
              required: ["id", "caption", "page", "headers", "rows"]
            }
          },
          debug_summary: { type: Type.STRING }
        },
        required: ["title", "summary", "researchQuestion", "methodology", "keyFindings", "limitations", "contributions", "citations", "tables"]
      }
    }
  });

  const rawData = JSON.parse(response.text);

  // Post-process tables to validate numeric data
  const processedTables = rawData.tables.map((table: any): TableData => {
    let isValid = true;
    const csvRows = [table.headers.join(','), ...table.rows.map((row: any[]) => row.join(','))];
    const csv = csvRows.join('\n');

    // Validation logic: ensure at least one column is numeric (besides first col)
    const hasNumericData = table.rows.some((row: any[]) => {
      return row.slice(1).some(cell => !isNaN(parseFloat(cell)));
    });

    if (!hasNumericData) isValid = false;

    return {
      ...table,
      validated: isValid,
      csv: csv
    };
  });

  return {
    ...rawData,
    tables: processedTables,
    charts: [] // Populated by chartService later
  };
}

import React, { useState, useRef } from 'react';
import { Upload, FileText, Loader2 } from 'lucide-react';

interface Props {
  onFileSelect: (file: File) => void;
  isLoading: boolean;
}

const PaperUploader: React.FC<Props> = ({ onFileSelect, isLoading }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelect(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
  };

  return (
    <div className="max-w-2xl mx-auto mt-12 px-4">
      <div 
        className={`relative p-12 border-2 border-dashed rounded-2xl transition-all duration-300 bg-white
          ${dragActive ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-indigo-400'}
          ${isLoading ? 'opacity-50 pointer-events-none' : ''}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input 
          ref={inputRef}
          type="file" 
          className="hidden" 
          accept=".pdf" 
          onChange={handleChange}
        />

        <div className="flex flex-col items-center justify-center space-y-4 text-center">
          {isLoading ? (
            <>
              <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
              <div className="space-y-2">
                <p className="text-xl font-semibold text-slate-800">Analyzing Research Paper...</p>
                <p className="text-sm text-slate-500">Extracting text, layout, and data tables...</p>
              </div>
            </>
          ) : (
            <>
              <div className="p-4 bg-indigo-100 rounded-full">
                <Upload className="w-8 h-8 text-indigo-600" />
              </div>
              <div className="space-y-2">
                <p className="text-xl font-semibold text-slate-800">Drop your research paper PDF</p>
                <p className="text-sm text-slate-500">Upload a single academic paper to generate an infographic</p>
              </div>
              <button 
                onClick={() => inputRef.current?.click()}
                className="px-6 py-2 text-sm font-medium text-white bg-indigo-600 rounded-lg hover:bg-indigo-700 transition-colors"
              >
                Select File
              </button>
            </>
          )}
        </div>
      </div>

      {!isLoading && (
        <div className="mt-8 flex items-center justify-center gap-6 text-slate-400 grayscale opacity-60">
            <div className="flex items-center gap-2"><FileText size={18} /> <span>Accurate Summaries</span></div>
            <div className="flex items-center gap-2"><FileText size={18} /> <span>Verified Citations</span></div>
            <div className="flex items-center gap-2"><FileText size={18} /> <span>Visual Charts</span></div>
        </div>
      )}
    </div>
  );
};

