import React, { useState } from 'react';
import { extractTextFromPDF } from './services/pdfService';
import { analyzePaper } from './services/geminiService';
import { generateSVGChart } from './services/chartService';
import { InfographicData } from './types';
import PaperUploader from './components/PaperUploader';
import InfographicViewer from './components/InfographicViewer';
import { Layers, HelpCircle, FileBarChart } from 'lucide-react';

const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<InfographicData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    setIsLoading(true);
    setError(null);
    try {
      // Phase A: Ingest & Structure
      const pages = await extractTextFromPDF(file);

      // Phase B-D: Analysis (Gemini)
      const data = await analyzePaper(pages);

      // Phase E: Tool Orchestration (Chart Gen)
      const charts = data.tables
        .map(table => generateSVGChart(table))
        .filter((c): c is any => c !== null)
        .slice(0, 2); // Limit to 2 charts max as per requirement

      setResult({ ...data, charts });
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An unexpected error occurred during paper analysis.');
    } finally {
      setIsLoading(false);
    }
  };

