/**
 * Helper to clean the response text in case the model wraps it in markdown blocks
 * despite the responseMimeType setting.
 */
function cleanJsonResponse(text: string): string {
  return text.trim().replace(/^```json\n?/, "").replace(/\n?```$/, "").trim();
}

/**
 * Exponential backoff utility for retrying failed API calls.
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  initialDelay: number = 1000
): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (err: any) {
      lastError = err;
      // If it's a 4xx error (other than 429), don't retry as it's likely a client issue
      if (err.status && err.status >= 400 && err.status < 500 && err.status !== 429) {
        throw err;
      }
      const delay = initialDelay * Math.pow(2, i);
      console.warn(`API call failed (attempt ${i + 1}/${maxRetries}). Retrying in ${delay}ms...`, err);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
  throw lastError;
}

export async function analyzePaper(pages: { pageNumber: number; text: string }[]): Promise<InfographicData> {
  const fullText = pages.map(p => `Page ${p.pageNumber}: ${p.text}`).join('\n\n');
  const modelName = 'gemini-3-pro-preview';

  const performAnalysis = async () => {
    // Create a new instance for every attempt to ensure a fresh session/key state
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    return await ai.models.generateContent({
      model: modelName,
      contents: `Analyze the following research paper text and extract information for a self-contained infographic.

      Constraints:
      - No invented facts.
      - Every claim must have a citation (page number and short quote).
      - Identify any tabular data for chart generation.
      - Be concise and clear.

      PAPER TEXT:
      ${fullText.slice(0, 25000)} // Slightly more conservative truncation to ensure proxy stability
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            summary: { type: Type.STRING },
            researchQuestion: { type: Type.STRING },
            methodology: { type: Type.STRING },
            keyFindings: { type: Type.STRING },
            limitations: { type: Type.STRING },
            contributions: { type: Type.STRING },
            citations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  section: { type: Type.STRING },
                  page: { type: Type.NUMBER },
                  quote: { type: Type.STRING }
                },
                required: ["section", "page", "quote"]
              }
            },
            tables: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  caption: { type: Type.STRING },
                  page: { type: Type.NUMBER },
                  headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                  rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } }
                },
                required: ["id", "caption", "page", "headers", "rows"]
              }
            },
            debug_summary: { type: Type.STRING }
          },
          required: ["title", "summary", "researchQuestion", "methodology", "keyFindings", "limitations", "contributions", "citations", "tables"]
        }
      }
    });
  };

  const response = await retryWithBackoff(performAnalysis);

  if (!response.text) {
    throw new Error("The model returned an empty response.");
  }

  const rawData = JSON.parse(cleanJsonResponse(response.text));

  // Post-process tables to validate numeric data
  const processedTables = (rawData.tables || []).map((table: any): TableData => {
    let isValid = true;
    const csvRows = [
      (table.headers || []).join(','), 
      ...(table.rows || []).map((row: any[]) => row.join(','))
    ];
    const csv = csvRows.join('\n');

    // Validation logic: ensure at least one column is numeric (besides first col)
    const hasNumericData = (table.rows || []).some((row: any[]) => {
      return row.slice(1).some(cell => {
        const val = parseFloat(cell);
        return !isNaN(val) && isFinite(val);
      });
    });

    if (!hasNumericData) isValid = false;

    return {
      id: table.id || Math.random().toString(36).substr(2, 9),
      caption: table.caption || "Table",
      page: table.page || 0,
      headers: table.headers || [],
      rows: table.rows || [],
      validated: isValid,
      csv: csv
    };
  });

  return {
    title: rawData.title || "Untitled Paper",
    summary: rawData.summary || "",
    researchQuestion: rawData.researchQuestion || "",
    methodology: rawData.methodology || "",
    keyFindings: rawData.keyFindings || "",
    limitations: rawData.limitations || "",
    contributions: rawData.contributions || "",
    citations: rawData.citations || [],
    tables: processedTables,
    charts: [], 
    debug_summary: rawData.debug_summary || ""
  };
}

