import { TableData, InfographicAsset } from '../types';

export function generateSVGChart(table: TableData): InfographicAsset | null {
  if (!table.validated || table.rows.length < 1 || table.headers.length < 2) return null;

  // Constants for high legibility
  const width = 800;
  const rowHeight = 40;
  const headerHeight = 60;
  const footerHeight = 40;
  const margin = { top: 44, right: 40, bottom: 64, left: 160 }; // Large left margin for long labels (e.g. countries)

  // Identify numeric column for X-axis (value)
  let valIdx = -1;
  for (let i = 1; i < table.headers.length; i++) {
    if (table.rows.some(row => !isNaN(parseFloat(String(row[i]).replace(/[%,]/g, ''))))) {
      valIdx = i;
      break;
    }
  }

  if (valIdx === -1) return null;

  // Process data - if ranking, take Top 10
  let data = table.rows.map(row => ({
    label: String(row[0]).trim(),
    value: parseFloat(String(row[valIdx]).replace(/[%,]/g, ''))
  })).filter(d => !isNaN(d.value));

  if (table.type === 'ranking') {
    data = data.sort((a, b) => b.value - a.value).slice(0, 10);
  } else {
    data = data.slice(0, 10); // Still limit to Top 10 for legibility
  }

  const chartHeight = data.length * rowHeight + margin.top + margin.bottom;
  const innerWidth = width - margin.left - margin.right;
  const innerHeight = data.length * rowHeight;

  const maxValue = Math.max(...data.map(d => d.value), 0) * 1.1;
  const unit = table.unit || "";

  // Render bars
  const bars = data.map((d, i) => {
    const barWidth = maxValue > 0 ? (d.value / maxValue) * innerWidth : 0;
    const y = margin.top + i * rowHeight + (rowHeight * 0.2);
    const barH = rowHeight * 0.6;

    // Label truncation if needed
    const displayLabel = d.label.length > 20 ? d.label.substring(0, 17) + "..." : d.label;

    return `
      <g class="bar-group">
        <text x="${margin.left - 10}" y="${y + barH/2 + 5}" text-anchor="end" font-size="13" fill="#374151" font-weight="500">${displayLabel}</text>
        <rect x="${margin.left}" y="${y}" width="${barWidth}" height="${barH}" fill="#4F46E5" rx="3" />
        <text x="${margin.left + barWidth + 8}" y="${y + barH/2 + 5}" text-anchor="start" font-size="12" fill="#6B7280" font-weight="600">${d.value.toLocaleString()} ${unit}</text>
      </g>
    `;
  }).join('');

  // X-axis Ticks (Value axis)
  const tickCount = 5;
  const ticks = Array.from({ length: tickCount + 1 }).map((_, i) => {
    const val = (maxValue / tickCount) * i;
    const x = margin.left + (val / maxValue) * innerWidth;
    return `
      <g class="tick">
        <line x1="${x}" y1="${margin.top}" x2="${x}" y2="${margin.top + innerHeight}" stroke="#F3F4F6" />
        <line x1="${x}" y1="${margin.top + innerHeight}" x2="${x}" y2="${margin.top + innerHeight + 5}" stroke="#9CA3AF" />
        <text x="${x}" y="${margin.top + innerHeight + 20}" text-anchor="middle" font-size="10" fill="#9CA3AF">${val.toFixed(1)}</text>
      </g>
    `;
  }).join('');

  const svg = `
    <svg width="${width}" height="${chartHeight}" viewBox="0 0 ${width} ${chartHeight}" xmlns="http://www.w3.org/2000/svg" style="background: white; border-radius: 8px;">
      <text x="${width / 2}" y="25" text-anchor="middle" font-weight="bold" font-size="16" fill="#111827">${table.caption}</text>
      <line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + innerHeight}" stroke="#E5E7EB" stroke-width="2" />
      <line x1="${margin.left}" y1="${margin.top + innerHeight}" x2="${margin.left + innerWidth}" y2="${margin.top + innerHeight}" stroke="#E5E7EB" stroke-width="2" />
      ${ticks}
      ${bars}
    </svg>
  `;

  return {
    id: `chart_${table.id}`,
    title: table.caption,
    source_table_id: table.id,
    source_page: table.page,
    svg: svg
  };
}

import { GoogleGenAI, Type } from "@google/genai";
import { InfographicData, TableData, TableCandidate, Citation } from "../types";

function cleanJsonResponse(text: string): string {
  return text.trim().replace(/^```json\n?/, "").replace(/\n?```$/, "").trim();
}

async function retryWithBackoff<T>(fn: () => Promise<T>, maxRetries: number = 3): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (err: any) {
      lastError = err;
      if (err.status && err.status >= 400 && err.status < 500 && err.status !== 429) throw err;
      await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, i)));
    }
  }
  throw lastError;
}

/**
 * PASS 1: Detect Table Candidates page-by-page.
 */
async function detectCandidates(pages: { pageNumber: number; text: string }[]): Promise<TableCandidate[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const candidates: TableCandidate[] = [];

  // Group pages into batches to respect token limits while ensuring full scan
  const BATCH_SIZE = 10;
  for (let i = 0; i < pages.length; i += BATCH_SIZE) {
    const batch = pages.slice(i, i + BATCH_SIZE);
    const context = batch.map(p => `--- PAGE ${p.pageNumber} ---\n${p.text}`).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Identify table or ranking list candidates in the following paper text. 
      Look for: 
      1. Numeric alignment patterns.
      2. Ranking markers (Country Name + decimal score).
      3. Captions like "Table X", "Figure Y", "Index", "Rankings".

      Return JSON list of objects: { "id": "string", "page": number, "caption": "string", "reason": "string", "context": "lines from the table" }

      TEXT:
      ${context}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            candidates: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  page: { type: Type.NUMBER },
                  caption: { type: Type.STRING },
                  reason: { type: Type.STRING },
                  context: { type: Type.STRING }
                },
                required: ["id", "page", "caption", "reason", "context"]
              }
            }
          }
        }
      }
    });

    try {
      const data = JSON.parse(cleanJsonResponse(response.text));
      candidates.push(...data.candidates.map((c: any) => ({
        id: c.id,
        page: c.page,
        caption_or_anchor_text: c.caption,
        raw_lines: c.context,
        detection_reason: c.reason
      })));
    } catch (e) {
      console.warn("Failed to parse candidates for batch", i, e);
    }
  }
  return candidates;
}

/**
 * PASS 2: Reconstruct structured TableData from candidates.
 */
async function reconstructTables(candidates: TableCandidate[]): Promise<TableData[]> {
  if (candidates.length === 0) return [];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Only process up to 5 best candidates to save time/tokens
  const bestCandidates = candidates.slice(0, 5);
  const tables: TableData[] = [];

  for (const cand of bestCandidates) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Reconstruct this candidate table into a structured JSON grid.
      Type should be 'ranking' if it's a list of scores for entities (like countries), otherwise 'standard'.
      Clean numeric cells: remove thousands separators, footnote marks (*, †), and separate uncertainty (parentheses) if present.

      CANDIDATE FROM PAGE ${cand.page}:
      "${cand.caption_or_anchor_text}"
      ${cand.raw_lines}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            headers: { type: Type.ARRAY, items: { type: Type.STRING } },
            rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
            type: { type: Type.STRING },
            unit: { type: Type.STRING },
            caption: { type: Type.STRING }
          },
          required: ["headers", "rows", "type", "caption"]
        }
      }
    });

    try {
      const data = JSON.parse(cleanJsonResponse(response.text));

      // Validation Logic
      let numericCount = 0;
      let totalCells = 0;
      data.rows.forEach((row: any[]) => {
        row.slice(1).forEach(cell => {
          totalCells++;
          const val = parseFloat(String(cell).replace(/[%,]/g, ''));
          if (!isNaN(val)) numericCount++;
        });
      });
      const isValid = totalCells > 0 ? (numericCount / totalCells) >= 0.8 : false;

      tables.push({
        id: cand.id,
        page: cand.page,
        caption: data.caption || cand.caption_or_anchor_text,
        headers: data.headers,
        rows: data.rows,
        type: data.type === 'ranking' ? 'ranking' : 'standard',
        unit: data.unit || "",
        validated: isValid,
        csv: [data.headers.join(','), ...data.rows.map((r:any[]) => r.join(','))].join('\n'),
        debug_reason: isValid ? "Successfully validated numeric columns." : "Failed numeric threshold validation."
      });
    } catch (e) {
      console.error("Reconstruction failed for candidate", cand.id, e);
    }
  }
  return tables;
}

/**
 * PASS 3: Summary & Citations.
 */
async function generateNarrative(pages: { pageNumber: number; text: string }[], tables: TableData[]): Promise<Partial<InfographicData>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Use first 5 and last 5 pages for context if it's a long report
  const selectedPages = pages.length > 20 ? [...pages.slice(0, 10), ...pages.slice(-5)] : pages;
  const contextText = selectedPages.map(p => `Page ${p.pageNumber}: ${p.text}`).join('\n\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Write a narrative summary for an infographic based on this research.

    Sections:
    - Core research question (1-2 sentences)
    - Methodology (briefly describe experimental or analytical setup)
    - Key findings (incorporate results from these tables if relevant: ${tables.filter(t => t.validated).map(t => t.caption).join(', ')})
    - Limitations
    - Contributions

    Rules:
    - Strictly support every claim with a quote snippet and page number.
    - Be concise.

    TEXT:
    ${contextText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          researchQuestion: { type: Type.STRING },
          methodology: { type: Type.STRING },
          keyFindings: { type: Type.STRING },
          limitations: { type: Type.STRING },
          contributions: { type: Type.STRING },
          citations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                section: { type: Type.STRING },
                page: { type: Type.NUMBER },
                quote: { type: Type.STRING }
              },
              required: ["section", "page", "quote"]
            }
          }
        },
        required: ["title", "summary", "researchQuestion", "methodology", "keyFindings", "limitations", "contributions", "citations"]
      }
    }
  });

  return JSON.parse(cleanJsonResponse(response.text));
}

export async function analyzePaper(pages: { pageNumber: number; text: string }[]): Promise<InfographicData> {
  // Step 1: Detect Table Candidates (Full Document Scan)
  const candidates = await retryWithBackoff(() => detectCandidates(pages));

  // Step 2: Reconstruct Found Tables
  const structuredTables = await retryWithBackoff(() => reconstructTables(candidates));

  // Step 3: Narrative Summary
  const narrative = await retryWithBackoff(() => generateNarrative(pages, structuredTables));

  return {
    ...narrative as InfographicData,
    tables: structuredTables,
    table_candidates: candidates,
    charts: [], // Populated by main App flow
    debug_summary: `Scanned ${pages.length} pages. Detected ${candidates.length} table candidates. Reconstructed ${structuredTables.length} tables.`
  };
}

