const pdfjsLib = window['pdfjs-dist/build/pdf'];
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

export async function extractTextFromPDF(file: File): Promise<{ pageNumber: number; text: string }[]> {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  const pages: { pageNumber: number; text: string }[] = [];

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const strings = content.items.map((item: any) => item.str);
    pages.push({
      pageNumber: i,
      text: strings.join(' '),
    });
  }

  return pages;
}

export async function renderPageToImage(file: File, pageNumber: number, scale: number = 1.5): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;
  const page = await pdf.getPage(pageNumber);

  const viewport = page.getViewport({ scale });
  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d');
  if (!context) throw new Error("Could not create canvas context");

  canvas.height = viewport.height;
  canvas.width = viewport.width;

  await page.render({
    canvasContext: context,
    viewport: viewport
  }).promise;

  return canvas.toDataURL('image/png').split(',')[1];
}

import { GoogleGenAI, Type } from "@google/genai";
import { InfographicData, TableData, TableCandidate, Citation } from "../types";
import { renderPageToImage } from "./pdfService";

function cleanJsonResponse(text: string): string {
  return text.trim().replace(/^```json\n?/, "").replace(/\n?```$/, "").trim();
}

async function retryWithBackoff<T>(fn: () => Promise<T>, maxRetries: number = 3): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (err: any) {
      lastError = err;
      if (err.status && err.status >= 400 && err.status < 500 && err.status !== 429) throw err;
      await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, i)));
    }
  }
  throw lastError;
}

/**
 * TEXT PASS 1: Detect Table Candidates.
 */
async function detectCandidates(pages: { pageNumber: number; text: string }[]): Promise<TableCandidate[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const candidates: TableCandidate[] = [];
  const BATCH_SIZE = 10;

  for (let i = 0; i < pages.length; i += BATCH_SIZE) {
    const batch = pages.slice(i, i + BATCH_SIZE);
    const context = batch.map(p => `--- PAGE ${p.pageNumber} ---\n${p.text}`).join('\n\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Identify table or ranking list candidates in the following paper text. 
      Look for: 
      1. Numeric alignment patterns.
      2. Ranking markers (Country Name + decimal score).
      3. Captions like "Table X", "Figure Y", "Index", "Rankings".

      Return JSON list of objects: { "candidates": [{ "id": "string", "page": number, "caption": "string", "reason": "string", "context": "lines from the table" }] }`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            candidates: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  page: { type: Type.NUMBER },
                  caption: { type: Type.STRING },
                  reason: { type: Type.STRING },
                  context: { type: Type.STRING }
                },
                required: ["id", "page", "caption", "reason", "context"]
              }
            }
          }
        }
      }
    });

    try {
      const data = JSON.parse(cleanJsonResponse(response.text));
      candidates.push(...data.candidates.map((c: any) => ({
        id: c.id,
        page: c.page,
        caption_or_anchor_text: c.caption,
        raw_lines: c.context,
        detection_reason: c.reason
      })));
    } catch (e) {
      console.warn("Failed to parse candidates for batch", i, e);
    }
  }
  return candidates;
}

/**
 * TEXT PASS 2: Reconstruct Table Data.
 */
async function reconstructTables(candidates: TableCandidate[]): Promise<TableData[]> {
  if (candidates.length === 0) return [];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const tables: TableData[] = [];

  for (const cand of candidates.slice(0, 5)) {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Reconstruct this candidate table into a structured JSON grid.
      Type should be 'ranking' if it's a list of scores for entities, otherwise 'standard'.
      Clean numeric cells: remove thousands separators, footnote marks, parentheses uncertainty.

      CANDIDATE FROM PAGE ${cand.page}:
      "${cand.caption_or_anchor_text}"
      ${cand.raw_lines}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            headers: { type: Type.ARRAY, items: { type: Type.STRING } },
            rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
            type: { type: Type.STRING },
            unit: { type: Type.STRING },
            caption: { type: Type.STRING }
          },
          required: ["headers", "rows", "type", "caption"]
        }
      }
    });

    try {
      const data = JSON.parse(cleanJsonResponse(response.text));
      const table = validateAndNormalizeTable(data, cand.page, cand.id, 'text');
      tables.push(table);
    } catch (e) {
      console.error("Reconstruction failed", e);
    }
  }
  return tables;
}

/**
 * VISION FALLBACK: Triage and extract tables from images.
 */
async function runVisionFallback(file: File, pageCount: number): Promise<TableData[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const visionTables: TableData[] = [];

  // Triage every page (up to a reasonable limit for large PDFs)
  const maxPages = Math.min(pageCount, 50); 

  for (let p = 1; p <= maxPages; p++) {
    try {
      const b64Image = await renderPageToImage(file, p);

      // Step 1: Triage
      const triageResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [
          { inlineData: { data: b64Image, mimeType: 'image/png' } },
          { text: "Identify if this PDF page contains a table or ranking list. Return JSON with 'has_table' (boolean), 'confidence' (0-1), and 'reasons' (string)." }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              has_table: { type: Type.BOOLEAN },
              confidence: { type: Type.NUMBER },
              reasons: { type: Type.STRING }
            }
          }
        }
      });

      const triage = JSON.parse(cleanJsonResponse(triageResponse.text));

      if (triage.has_table && triage.confidence >= 0.6) {
        // Step 2: Extract
        const extractResponse = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: [
            { inlineData: { data: b64Image, mimeType: 'image/png' } },
            { text: "Extract every table on this page into a structured format. Return JSON only with a list of 'tables'. Each table must have id, caption, page, headers (string[]), rows (string[][]), and extraction_confidence." }
          ],
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                tables: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      caption: { type: Type.STRING },
                      page: { type: Type.NUMBER },
                      headers: { type: Type.ARRAY, items: { type: Type.STRING } },
                      rows: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } },
                      extraction_confidence: { type: Type.NUMBER }
                    }
                  }
                }
              }
            }
          }
        });

        const extractData = JSON.parse(cleanJsonResponse(extractResponse.text));
        for (const rawTable of extractData.tables) {
          const table = validateAndNormalizeTable(rawTable, p, rawTable.id || `vision_${p}`, 'vision');
          table.extraction_confidence = rawTable.extraction_confidence;
          visionTables.push(table);
        }
      }
    } catch (err) {
      console.warn(`Vision pass failed for page ${p}`, err);
    }
  }
  return visionTables;
}

function validateAndNormalizeTable(data: any, page: number, id: string, source: 'text' | 'vision'): TableData {
  let numericCount = 0;
  let totalCells = 0;

  data.rows.forEach((row: any[]) => {
    row.slice(1).forEach(cell => {
      totalCells++;
      const val = parseFloat(String(cell).replace(/[%,]/g, '').replace(/±.*/, ''));
      if (!isNaN(val) && isFinite(val)) numericCount++;
    });
  });

  const isValid = totalCells > 0 ? (numericCount / totalCells) >= 0.8 : false;

  return {
    id,
    page: data.page || page,
    caption: data.caption || "Extracted Table",
    headers: data.headers,
    rows: data.rows,
    type: (data.type === 'ranking' || data.caption?.toLowerCase().includes('rank')) ? 'ranking' : 'standard',
    unit: data.unit || "",
    validated: isValid,
    csv: [data.headers.join(','), ...data.rows.map((r: any[]) => r.join(','))].join('\n'),
    debug_reason: isValid ? "Validated numeric threshold." : "Low numeric cell ratio.",
    source
  };
}

/**
 * NARRATIVE PASS.
 */
async function generateNarrative(pages: { pageNumber: number; text: string }[], tables: TableData[]): Promise<Partial<InfographicData>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const selectedPages = pages.length > 20 ? [...pages.slice(0, 10), ...pages.slice(-5)] : pages;
  const contextText = selectedPages.map(p => `Page ${p.pageNumber}: ${p.text}`).join('\n\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Summarize this paper into an infographic. Include core research question, methodology, findings, limitations, and contributions.
    Available data tables: ${tables.filter(t => t.validated).map(t => t.caption).join(', ')}.

    TEXT:
    ${contextText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          researchQuestion: { type: Type.STRING },
          methodology: { type: Type.STRING },
          keyFindings: { type: Type.STRING },
          limitations: { type: Type.STRING },
          contributions: { type: Type.STRING },
          citations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: { section: { type: Type.STRING }, page: { type: Type.NUMBER }, quote: { type: Type.STRING } },
              required: ["section", "page", "quote"]
            }
          }
        },
        required: ["title", "summary", "researchQuestion", "methodology", "keyFindings", "limitations", "contributions", "citations"]
      }
    }
  });

  return JSON.parse(cleanJsonResponse(response.text));
}

export async function analyzePaper(pages: { pageNumber: number; text: string }[], file: File): Promise<InfographicData> {
  // Pass 1: Text-based Extraction
  const candidates = await retryWithBackoff(() => detectCandidates(pages));
  let structuredTables = await retryWithBackoff(() => reconstructTables(candidates));

  const validatedCount = structuredTables.filter(t => t.validated).length;
  let visionSummary = "";

  // Step 2: Vision Fallback if text extraction fails
  if (validatedCount === 0) {
    console.log("No validated tables found in text pass. Running vision fallback...");
    const visionResults = await runVisionFallback(file, pages.length);
    structuredTables = [...structuredTables, ...visionResults];
    visionSummary = ` Vision pass identified ${visionResults.length} additional tables.`;
  }

  // Step 3: Narrative
  const narrative = await retryWithBackoff(() => generateNarrative(pages, structuredTables));

  return {
    ...narrative as InfographicData,
    tables: structuredTables,
    table_candidates: candidates,
    charts: [],
    debug_summary: `Processed ${pages.length} pages. Text Pass: ${candidates.length} candidates.${visionSummary}`
  };
}

