const App: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<InfographicData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    setIsLoading(true);
    setError(null);
    try {
      const pages = await extractTextFromPDF(file);
      const data = await analyzePaper(pages, file);

      const validTables = (data.tables || []).filter(t => t.validated);
      const rankingTables = validTables.filter(t => t.type === 'ranking');
      const standardTables = validTables.filter(t => t.type === 'standard');
      const tableSelection = [...rankingTables, ...standardTables].slice(0, 2);

      const charts = tableSelection
        .map(table => generateSVGChart(table))
        .filter((c): c is any => c !== null);

      setResult({ ...data, charts });
    } catch (err: any) {
      console.error("Extraction error:", err);
      setError(err.message || 'An unexpected error occurred during analysis.');
    } finally {
      setIsLoading(false);
    }
  };

  const loadDemo = () => {
    const charts = SAMPLE_DATA.tables
      .map(table => generateSVGChart(table as TableData))
      .filter((c): c is any => c !== null);
    setResult({ ...SAMPLE_DATA, charts });
  };

  return (
    <div className="min-h-screen bg-[#FDFCFB]">
