          {data.charts.map((chart, idx) => (
            <div key={idx} className="col-span-2 space-y-4 pt-4">
              <div dangerouslySetInnerHTML={{ __html: chart.svg }} className="w-full" />
              <div className="text-[9px] font-bold uppercase tracking-widest text-slate-300 text-center">Verified Evidence: Page {chart.source_page}</div>
            </div>
          ))}

          <DetailSection title="Research Objective" content={data.researchQuestion} citations={data.citations.filter(c => c.section.includes("Research"))} />
          <DetailSection title="Methodology" content={data.methodology} citations={data.citations.filter(c => c.section.includes("Methods"))} />
          <DetailSection title="Limitations" content={data.limitations} citations={data.citations.filter(c => c.section.includes("Limitations"))} />
          <DetailSection title="Contribution" content={data.contributions} citations={data.citations.filter(c => c.section.includes("Contributions"))} />
        </div>
      </div>

      {data.tables.length > 0 && (
        <section className="max-w-[840px] mx-auto space-y-8 pt-12 border-t border-slate-100">
            <h3 className="text-[10px] font-bold uppercase tracking-[0.3em] text-slate-400 flex items-center gap-2">
                <Database size={12} />
                Extracted Datasets
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {data.tables.map((table, i) => (
                    <div key={i} className="flex items-center justify-between p-6 bg-white border border-slate-100 rounded-xl hover:border-slate-200 transition-all">
                        <div className="space-y-1">
                            <p className="text-xs font-semibold text-slate-900 truncate max-w-[200px]">{table.caption || `Dataset ${i+1}`}</p>
                            <p className="text-[9px] font-bold uppercase tracking-widest text-slate-400">Page {table.page} • {table.source}</p>
                        </div>
                        <button 
                            onClick={() => handleDownloadCSV(table)}
                            className="p-3 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all"
                        >
                            <Download size={14} />
                        </button>
                    </div>
                ))}
            </div>
        </section>
      )}
    </div>
  );
};

const DetailSection: React.FC<{title: string, content: string, citations: any[]}> = ({title, content, citations}) => (
  <div className="space-y-4">
    <h3 className="text-[10px] font-bold uppercase tracking-[0.3em] text-slate-400">{title}</h3>
    <p className="text-sm text-slate-700 font-light leading-relaxed">
      {content}
      {citations.map((c, i) => (
          <span key={i} title={c.quote} className="ml-2 cursor-help text-[8px] font-bold px-1.5 py-0.5 bg-slate-50 text-slate-400 border border-slate-100 rounded">P.{c.page}</span>
      ))}
    </p>
  </div>
);

export default InfographicViewer;
